public class Solution {
public int validateUniqueVowels(String S) {
    int unique = 0;
    HashSet<Character> vowels = new HashSet<>();
    vowels.add('a');
    vowels.add('e');
    vowels.add('i');
    vowels.add('o');
    vowels.add('u');
    for (int i = 0; i < S.length(); i++)
        if (vowels.contains(S.charAt(i)))
            if (i != S.length()-1 && vowels.contains(S.charAt(i+1)))
                unique = 1;
    return unique;
}}

